const p = msg.payload || {};

if (typeof p !== 'object' || p === null || Array.isArray(p)) {
    msg.error = 'payload no es un objeto JSON valido';
    return [null, msg];
}

function toNumberOrNull(v) {
    if (v === null || v === undefined || v === '') return null;
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
}

function toBoolean(v, fallback = false) {
    if (typeof v === 'boolean') return v;
    if (typeof v === 'number') return v > 0;
    if (typeof v === 'string') {
        const x = v.trim().toLowerCase();
        return x === '1' || x === 'true' || x === 'on' || x === 'si' || x === 'yes';
    }
    return fallback;
}

function normalizeTimestamp(raw) {
    if (raw === null || raw === undefined || raw === '') return null;

    if (typeof raw === 'number' && Number.isFinite(raw)) {
        const epoch = raw < 1e12 ? raw * 1000 : raw;
        const dt = new Date(epoch);
        return Number.isFinite(dt.getTime()) ? dt.toISOString() : null;
    }

    if (typeof raw === 'string') {
        const value = raw.trim();
        if (!value) return null;

        if (/^\d+$/.test(value)) {
            const epoch = Number(value);
            if (Number.isFinite(epoch)) {
                const ms = epoch < 1e12 ? epoch * 1000 : epoch;
                const dtEpoch = new Date(ms);
                return Number.isFinite(dtEpoch.getTime()) ? dtEpoch.toISOString() : null;
            }
        }

        const parsed = Date.parse(value);
        if (Number.isFinite(parsed)) {
            return new Date(parsed).toISOString();
        }
    }

    return null;
}

let idHabitacion = String(p.id_habitacion ?? p.habitacion ?? p.room ?? '').trim();
const contextoRaw = String(p.contexto_hotel ?? p.room_context ?? 'LIBRE').trim().toUpperCase();
const contextoHotel = ['LIBRE', 'RESERVADA', 'FUMIGACION'].includes(contextoRaw) ? contextoRaw : 'LIBRE';
const rawTimestamp = p.timestamp ?? p.timestamp_ms ?? Date.now();
let timestamp = normalizeTimestamp(rawTimestamp);
const temperaturaC = toNumberOrNull(p.temperatura_C ?? p.temperature_C);
const humedadPct = toNumberOrNull(p.humedad_pct ?? p.humidity_pct);
const fosfinaMq135 = toNumberOrNull(p.fosfina_mq135 ?? p.mq135);
const coMq7 = toNumberOrNull(p.co_mq7 ?? p.mq7);
const ph3Ppm = toNumberOrNull(p.ph3_ppm);
const coPpm = toNumberOrNull(p.co_ppm);
const intervaloEnvioMs = toNumberOrNull(p.intervalo_envio_ms);
const presenciaPir = toBoolean(p.presencia_pir ?? p.motion, false);
const dhtOk = typeof p.dht_ok === 'boolean' ? p.dht_ok : null;

const out = {
    id_habitacion: idHabitacion || 'DESCONOCIDO',
    contexto_hotel: contextoHotel,
    timestamp: timestamp || new Date().toISOString(),
    sistema_activo: typeof p.sistema_activo === 'boolean' ? p.sistema_activo : null,
    intervalo_envio_ms: intervaloEnvioMs,
    fosfina_mq135: fosfinaMq135,
    co_mq7: coMq7,
    presencia_pir: presenciaPir,
    evento_pir: p.evento_pir ? String(p.evento_pir) : null,
    temperatura_C: temperaturaC,
    humedad_pct: humedadPct,
    ph3_ppm: ph3Ppm,
    co_ppm: coPpm,
    dht_ok: dhtOk,
    error: p.error ? String(p.error) : null
};

const issues = [];
const markIssue = (issue) => {
    if (issue && !issues.includes(issue)) {
        issues.push(issue);
    }
};

if (!idHabitacion) markIssue('id_habitacion_faltante');
if (!timestamp) markIssue('timestamp_invalido');
if (contextoRaw && contextoRaw !== contextoHotel) markIssue('contexto_normalizado');
if (!Number.isFinite(fosfinaMq135)) markIssue('fosfina_mq135_invalido');
if (!Number.isFinite(coMq7)) markIssue('co_mq7_invalido');
if (!Number.isFinite(temperaturaC) && dhtOk !== false) markIssue('temperatura_faltante');
if (!Number.isFinite(humedadPct) && dhtOk !== false) markIssue('humedad_faltante');
if (Number.isFinite(temperaturaC) && (temperaturaC < -20 || temperaturaC > 80)) markIssue('temperatura_fuera_rango');
if (Number.isFinite(humedadPct) && (humedadPct < 0 || humedadPct > 100)) markIssue('humedad_fuera_rango');
if (Number.isFinite(intervaloEnvioMs) && (intervaloEnvioMs < 1000 || intervaloEnvioMs > 60000)) markIssue('intervalo_fuera_rango');
if (dhtOk === false) markIssue('dht_fallo');
if (out.error) markIssue('error_sensor');

const parsedTimestamp = Date.parse(timestamp);
if (Number.isFinite(parsedTimestamp)) {
    const lastTsKey = 'last_timestamp_' + (idHabitacion || 'desconocido');
    const lastTs = Number(flow.get(lastTsKey) || 0);
    const gapLimit = Number.isFinite(intervaloEnvioMs) && intervaloEnvioMs > 0
        ? Math.max(intervaloEnvioMs * 3, 30000)
        : Number(env.get('TEMPORAL_GAP_MAX_MS') || 120000);
    if (lastTs > 0) {
        const gap = parsedTimestamp - lastTs;
        if (gap > gapLimit) {
            markIssue('hueco_temporal_' + gap + 'ms');
        }
    }
    flow.set(lastTsKey, parsedTimestamp);
}

const issueCount = issues.length;
const estadoCalidad = issueCount === 0 ? 'OK' : (issueCount === 1 ? 'OBSERVADO' : 'MULTIPLE');
const motivoCalidad = issueCount > 0 ? issues.join('; ') : null;
const firmaMedicion = [
    out.id_habitacion,
    out.timestamp,
    out.contexto_hotel,
    Number.isFinite(out.temperatura_C) ? out.temperatura_C.toFixed(2) : 'NULL',
    Number.isFinite(out.humedad_pct) ? out.humedad_pct.toFixed(2) : 'NULL',
    Number.isFinite(out.fosfina_mq135) ? out.fosfina_mq135.toFixed(2) : 'NULL',
    Number.isFinite(out.co_mq7) ? out.co_mq7.toFixed(2) : 'NULL',
    Number.isFinite(out.ph3_ppm) ? out.ph3_ppm.toFixed(2) : 'NULL',
    Number.isFinite(out.co_ppm) ? out.co_ppm.toFixed(2) : 'NULL',
    out.presencia_pir ? 1 : 0,
    Number.isFinite(out.intervalo_envio_ms) ? out.intervalo_envio_ms : 'NULL'
].join('|');

msg.rawPayload = p;
msg.validation_issues = issues;
msg.payload = {
    ...out,
    tiene_problema: issueCount > 0 ? 1 : 0,
    estado_calidad: estadoCalidad,
    motivo_calidad: motivoCalidad,
    firma_medicion: firmaMedicion
};

return [msg, null];

const p = msg.payload || {};

const contextFromPayload = String(p.contexto_hotel || '').toUpperCase();
const validContexts = ['LIBRE', 'RESERVADA', 'FUMIGACION'];
let contexto = flow.get('estado_habitacion') || 'LIBRE';
if (validContexts.includes(contextFromPayload) && contextFromPayload !== contexto) {
    contexto = contextFromPayload;
    flow.set('estado_habitacion', contexto);
}

const PH3_PEL = Number(env.get('PH3_PEL_PPM') || 0.3);
const PH3_STEL = Number(env.get('PH3_STEL_PPM') || 1.0);
const PH3_IRRIT_LOW = Number(env.get('PH3_IRRIT_LOW_PPM') || 5);
const PH3_IRRIT_HIGH = Number(env.get('PH3_IRRIT_HIGH_PPM') || 10);
const PH3_IDLH = Number(env.get('PH3_IDLH_PPM') || 50);
const PH3_LETHAL_LOW = Number(env.get('PH3_LETHAL_LOW_PPM') || 400);

const CO_PEL = Number(env.get('CO_PEL_PPM') || 50);
const CO_HEADACHE = Number(env.get('CO_HEADACHE_PPM') || 200);
const CO_STEL = Number(env.get('CO_STEL_PPM') || 400);
const CO_SEVERE = Number(env.get('CO_SEVERE_PPM') || 800);
const CO_IDLH = Number(env.get('CO_IDLH_PPM') || 1500);

const TEMP_ALERTA = Number(env.get('TEMP_ALERTA_C') || 35);
const TEMP_INCENDIO = Number(env.get('UMBRAL_TEMP_INCENDIO') || 45);
const HUM_RIESGO_MIN = Number(env.get('HUM_RIESGO_MIN_PCT') || 30);
const HUM_RIESGO_MAX = Number(env.get('HUM_RIESGO_MAX_PCT') || 60);

const MQ135_MIN = Number(env.get('MQ135_RAW_MIN') || 0);
const MQ135_MAX = Number(env.get('MQ135_RAW_MAX') || 4095);
const MQ7_MIN = Number(env.get('MQ7_RAW_MIN') || 0);
const MQ7_MAX = Number(env.get('MQ7_RAW_MAX') || 4095);
const MQ135_PPM_MAX = Number(env.get('PH3_PPM_MAX_EST') || 120);
const MQ7_PPM_MAX = Number(env.get('CO_PPM_MAX_EST') || 2000);

function clamp(v, lo, hi) {
    return Math.max(lo, Math.min(hi, v));
}

function mapRawToPpm(raw, inMin, inMax, outMax) {
    const x = clamp(Number(raw), inMin, inMax);
    const ratio = (x - inMin) / Math.max(1, (inMax - inMin));
    return ratio * outMax;
}

function hasNum(v) {
    return Number.isFinite(Number(v));
}

function fmt(v) {
    return Number.isFinite(Number(v)) ? Number(Number(v).toFixed(2)) : null;
}

const ph3Ppm = hasNum(p.ph3_ppm) ? Number(p.ph3_ppm) : mapRawToPpm(p.fosfina_mq135, MQ135_MIN, MQ135_MAX, MQ135_PPM_MAX);
const coPpm = hasNum(p.co_ppm) ? Number(p.co_ppm) : mapRawToPpm(p.co_mq7, MQ7_MIN, MQ7_MAX, MQ7_PPM_MAX);
const tempC = hasNum(p.temperatura_C) ? Number(p.temperatura_C) : null;
const humPct = hasNum(p.humedad_pct) ? Number(p.humedad_pct) : null;

const severity = { NORMAL: 0, ALERTA: 1, EMERGENCIA: 2 };
let estado = 'NORMAL';
let razon = 'sin_alertas';
let nivel_alerta = 'NORMAL';
let color_alerta = 'green';
const motivos = [];

function addMotivo(category, code, detail) {
    const base = `${category}:${code}`;
    motivos.push(detail ? `${base}|${detail}` : base);
    return base;
}

function setEstado(nuevoEstado, razonBase, nivel, color) {
    if (severity[nuevoEstado] > severity[estado]) {
        estado = nuevoEstado;
        razon = razonBase;
        nivel_alerta = nivel;
        color_alerta = color;
    }
}

if (contexto === 'FUMIGACION') {
    if (p.presencia_pir) {
        const reason = addMotivo('presencia', 'intruso_fumigacion', 'pir=1');
        setEstado('EMERGENCIA', reason, 'CRITICO: INTRUSO EN FUMIGACION', 'red');
    }
    if (ph3Ppm >= PH3_IDLH) {
        const reason = addMotivo('gas', 'ph3_idlh', `ph3_ppm=${fmt(ph3Ppm)}`);
        setEstado('EMERGENCIA', reason, 'CRITICO: FOSFINA SOBRE IDLH', 'red');
    }
    if (coPpm >= CO_IDLH) {
        const reason = addMotivo('gas', 'co_idlh', `co_ppm=${fmt(coPpm)}`);
        setEstado('EMERGENCIA', reason, 'CRITICO: CO IDLH', 'red');
    }
    if (tempC !== null && tempC >= TEMP_INCENDIO) {
        const reason = addMotivo('temperatura', 'incendio', `temp_C=${fmt(tempC)}`);
        setEstado('EMERGENCIA', reason, 'CRITICO: CONATO DE INCENDIO', 'red');
    }
    if (ph3Ppm >= PH3_PEL) {
        const reason = addMotivo('gas', 'ph3_pel', `ph3_ppm=${fmt(ph3Ppm)}`);
        setEstado('ALERTA', reason, 'ALERTA: FOSFINA SOBRE PEL', 'yellow');
    }
    if (coPpm >= CO_PEL) {
        const reason = addMotivo('gas', 'co_pel', `co_ppm=${fmt(coPpm)}`);
        setEstado('ALERTA', reason, 'ALERTA: CO SOBRE PEL', 'yellow');
    }
    if (tempC !== null && tempC >= TEMP_ALERTA) {
        const reason = addMotivo('temperatura', 'elevada', `temp_C=${fmt(tempC)}`);
        setEstado('ALERTA', reason, 'ALERTA: TEMPERATURA ELEVADA', 'yellow');
    }
} else {
    if (ph3Ppm >= PH3_LETHAL_LOW) {
        const reason = addMotivo('gas', 'ph3_letal', `ph3_ppm=${fmt(ph3Ppm)}`);
        setEstado('EMERGENCIA', reason, 'CRITICO: FOSFINA NIVEL LETAL', 'red');
    }
    if (coPpm >= CO_IDLH) {
        const reason = addMotivo('gas', 'co_idlh', `co_ppm=${fmt(coPpm)}`);
        setEstado('EMERGENCIA', reason, 'CRITICO: CO IDLH', 'red');
    }
    if (tempC !== null && tempC >= TEMP_INCENDIO) {
        const reason = addMotivo('temperatura', 'incendio', `temp_C=${fmt(tempC)}`);
        setEstado('EMERGENCIA', reason, 'CRITICO: CONATO DE INCENDIO', 'red');
    }
    if (ph3Ppm >= PH3_IDLH) {
        const reason = addMotivo('gas', 'ph3_idlh', `ph3_ppm=${fmt(ph3Ppm)}`);
        setEstado('ALERTA', reason, 'ALERTA: FOSFINA SOBRE IDLH', 'yellow');
    }
    if (coPpm >= CO_SEVERE) {
        const reason = addMotivo('gas', 'co_severo', `co_ppm=${fmt(coPpm)}`);
        setEstado('ALERTA', reason, 'ALERTA: CO NIVEL SEVERO', 'yellow');
    }
    if (tempC !== null && tempC >= TEMP_ALERTA) {
        const reason = addMotivo('temperatura', 'elevada', `temp_C=${fmt(tempC)}`);
        setEstado('ALERTA', reason, 'ALERTA: TEMPERATURA ELEVADA', 'yellow');
    }
    if (ph3Ppm >= PH3_IRRIT_LOW) {
        const reason = addMotivo('gas', 'ph3_irritacion', `ph3_ppm=${fmt(ph3Ppm)}`);
        setEstado('ALERTA', reason, 'ALERTA: IRRITACION POR FOSFINA', 'yellow');
    }
    if (coPpm >= CO_STEL) {
        const reason = addMotivo('gas', 'co_stel', `co_ppm=${fmt(coPpm)}`);
        setEstado('ALERTA', reason, 'ALERTA: CO SOBRE STEL', 'yellow');
    }
    if (ph3Ppm >= PH3_STEL) {
        const reason = addMotivo('gas', 'ph3_stel', `ph3_ppm=${fmt(ph3Ppm)}`);
        setEstado('ALERTA', reason, 'ALERTA: FOSFINA SOBRE STEL', 'yellow');
    }
    if (coPpm >= CO_HEADACHE) {
        const reason = addMotivo('gas', 'co_cefalea', `co_ppm=${fmt(coPpm)}`);
        setEstado('ALERTA', reason, 'ALERTA: CO POSIBLE CEFALEA', 'yellow');
    }
    if (ph3Ppm >= PH3_PEL) {
        const reason = addMotivo('gas', 'ph3_pel', `ph3_ppm=${fmt(ph3Ppm)}`);
        setEstado('ALERTA', reason, 'ALERTA: FOSFINA SOBRE PEL', 'yellow');
    }
    if (coPpm >= CO_PEL) {
        const reason = addMotivo('gas', 'co_pel', `co_ppm=${fmt(coPpm)}`);
        setEstado('ALERTA', reason, 'ALERTA: CO SOBRE PEL', 'yellow');
    }
}

if (Number.isFinite(humPct) && (humPct < HUM_RIESGO_MIN || humPct > HUM_RIESGO_MAX)) {
    const reason = addMotivo('humedad', 'fuera_rango', `hum_pct=${fmt(humPct)}`);
    setEstado('ALERTA', reason, 'ALERTA: HUMEDAD FUERA DE RANGO', 'yellow');
}

const statusText = String(p.id_habitacion || '') + ' | ' + estado;
if (estado === 'EMERGENCIA') {
    node.status({ fill: 'red', shape: 'dot', text: statusText.slice(0, 64) });
} else if (estado === 'ALERTA') {
    node.status({ fill: 'yellow', shape: 'dot', text: statusText.slice(0, 64) });
} else {
    node.status({ fill: 'green', shape: 'dot', text: statusText.slice(0, 64) });
}

const motivoActivacion = motivos.length ? motivos.join('; ') : 'sin_alertas';

msg.payload = {
    ...p,
    id_habitacion: p.id_habitacion,
    contexto_hotel: contexto,
    estado_riesgo: estado,
    razon_riesgo: razon,
    motivo_activacion: motivoActivacion,
    nivel_alerta,
    color_alerta,
    ph3_ppm: Number.isFinite(ph3Ppm) ? Number(ph3Ppm.toFixed(2)) : null,
    co_ppm: Number.isFinite(coPpm) ? Number(coPpm.toFixed(2)) : null,
    timestamp: p.timestamp,
    timestamp_servidor: new Date().toISOString()
};

return msg;

const p = msg.payload || {};

function toNumberOrNull(v, digits = null) {
    const n = Number(v);
    if (!Number.isFinite(n)) return null;
    return digits === null ? n : Number(n.toFixed(digits));
}

function toMysqlDateTime(isoLike) {
    const dt = new Date(isoLike);
    if (!Number.isFinite(dt.getTime())) {
        const now = new Date();
        return now.toISOString().slice(0, 19).replace('T', ' ');
    }
    return dt.toISOString().slice(0, 19).replace('T', ' ');
}

msg.idHabitacion = String(p.id_habitacion || 'N/A');
msg.contextoHotel = String(p.contexto_hotel || 'LIBRE');
msg.estadoRiesgo = String(p.estado_riesgo || 'INVALIDO').toUpperCase();
msg.razonRiesgo = String(p.razon_riesgo || 'sin_razon');
msg.nivelAlerta = String(p.nivel_alerta || 'N/A');
msg.colorAlerta = String(p.color_alerta || 'grey');

msg.topic = 'INSERT INTO mediciones_brutas (id_habitacion, contexto_hotel, temperatura_c, humedad_pct, fosfina_mq135, co_mq7, presencia_pir, intervalo_envio_ms, timestamp_origen) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)';
msg.payload = [
    msg.idHabitacion,
    msg.contextoHotel,
    toNumberOrNull(p.temperatura_C, 2),
    toNumberOrNull(p.humedad_pct, 2),
    toNumberOrNull(p.fosfina_mq135, 2),
    toNumberOrNull(p.co_mq7, 2),
    p.presencia_pir ? 1 : 0,
    toNumberOrNull(p.intervalo_envio_ms),
    toMysqlDateTime(p.timestamp)
];
msg.queryType = 'insert_bruta';

return msg;

const medicionId = Number(msg.payload && msg.payload.insertId);
if (!Number.isFinite(medicionId) || medicionId <= 0) {
    return null;
}

msg.medicionId = medicionId;
if (msg.idHabitacion) {
    flow.set(`last_medicion_${msg.idHabitacion}`, medicionId);
}

msg.topic = 'INSERT INTO estados_medicion (medicion_id, estado_riesgo, razon_riesgo, color_alerta) VALUES (?, ?, ?, ?)';
msg.payload = [
    medicionId,
    String(msg.estadoRiesgo || 'INVALIDO').toUpperCase(),
    String(msg.razonRiesgo || ''),
    String(msg.colorAlerta || 'grey')
];
msg.queryType = 'insert_estado';
return msg;

const src = msg.payload || {};
const risk = String(src.estado_riesgo || '').toUpperCase();
if (!['NORMAL', 'ALERTA', 'EMERGENCIA'].includes(risk)) return null;

const intervalByRisk = {
    NORMAL: Number(env.get('SAMPLE_MS_NORMAL') || 15000),
    ALERTA: Number(env.get('SAMPLE_MS_ALERTA') || 7000),
    EMERGENCIA: Number(env.get('SAMPLE_MS_EMERGENCIA') || 3000)
};

const intervalMs = Number(intervalByRisk[risk]);
if (!Number.isFinite(intervalMs) || intervalMs <= 0) return null;

const contexto = flow.get('estado_habitacion') || String(src.contexto_hotel || 'LIBRE').toUpperCase();
const idHabitacion = String(src.id_habitacion || '').trim();
if (!idHabitacion) return null;

const cooldownMs = Number(env.get('CMD_COOLDOWN_MS') || 15000);
const now = Date.now();
const lastAt = Number(flow.get('last_cmd_at') || 0);
const lastSig = flow.get('last_cmd_sig') || '';
const sig = `${idHabitacion}|${risk}|${contexto}|${intervalMs}`;

if ((now - lastAt) < cooldownMs && lastSig === sig) {
    return null;
}

flow.set('last_cmd_at', now);
flow.set('last_cmd_sig', sig);

msg.commandMeta = {
    id_habitacion: idHabitacion,
    estado_riesgo: risk,
    contexto_hotel: contexto,
    motivo_activacion: String(src.motivo_activacion || src.razon_riesgo || src.nivel_alerta || 'ajuste_automatico'),
    intervalo_objetivo_ms: intervalMs,
    timestamp_origen: src.timestamp || null
};

const baseTopic = env.get('TOPICO_COMANDOS') || 'alejandro.bravo_isa@uao.edu.co/comandos';
msg.topic = baseTopic;
msg.payload = {
    estado: contexto,
    sample_interval_ms: intervalMs,
    id_habitacion: idHabitacion
};
return msg;

const meta = msg.commandMeta || {};
if (!meta.id_habitacion) {
    return null;
}

function toMysqlDateTime(isoLike) {
    const dt = new Date(isoLike);
    if (!Number.isFinite(dt.getTime())) {
        return null;
    }
    return dt.toISOString().slice(0, 19).replace('T', ' ');
}

const lastId = flow.get(`last_medicion_${meta.id_habitacion}`);
const medicionId = Number.isFinite(Number(lastId)) ? Number(lastId) : null;

msg.topic = 'INSERT INTO eventos_actuadores (medicion_id, id_habitacion, estado_riesgo, contexto_hotel, motivo_activacion, intervalo_objetivo_ms, timestamp_origen) VALUES (?, ?, ?, ?, ?, ?, ?)';
msg.payload = [
    medicionId,
    String(meta.id_habitacion),
    String(meta.estado_riesgo || 'INVALIDO').toUpperCase(),
    String(meta.contexto_hotel || 'LIBRE').toUpperCase(),
    String(meta.motivo_activacion || 'sin_motivo'),
    Number.isFinite(Number(meta.intervalo_objetivo_ms)) ? Number(meta.intervalo_objetivo_ms) : null,
    toMysqlDateTime(meta.timestamp_origen)
];
msg.queryType = 'insert_evento';
return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [];

if (rows.length === 0) {
    msg.payload = 'Sin resultados';
    return msg;
}

const safe = (v) => String(v ?? '');
const maxRows = 20;
const data = rows.slice(0, maxRows);

const cols = Object.keys(data[0] || {}).sort((a, b) => a.localeCompare(b));
if (cols.length === 0) {
    msg.payload = 'Sin columnas para mostrar';
    return msg;
}

const widths = cols.map((c) => c.length);
for (const r of data) {
    cols.forEach((c, i) => {
        const l = safe(r[c]).length;
        if (l > widths[i]) widths[i] = Math.min(l, 40);
    });
}

const trunc = (s, w) => (s.length > w ? s.slice(0, w - 1) + '...' : s);
const pad = (s, w) => trunc(s, w).padEnd(w, ' ');

const header = cols.map((c, i) => pad(c, widths[i])).join(' | ');
const sep = widths.map((w) => '-'.repeat(w)).join('-+-');
const body = data.map((r) => cols.map((c, i) => pad(safe(r[c]), widths[i])).join(' | ')).join('\n');

msg.payload = `Filas devueltas: ${rows.length}\n\n${header}\n${sep}\n${body}`;
return msg;

const token = String(msg.payload || '').trim().toUpperCase();
const baseJoin = 'SELECT m.id, m.id_habitacion, m.contexto_hotel, m.temperatura_c, m.humedad_pct, m.fosfina_mq135, m.co_mq7, m.presencia_pir, m.intervalo_envio_ms, m.limpio, e.estado_riesgo, e.razon_riesgo, e.color_alerta, m.timestamp_origen, m.created_at FROM mediciones_brutas m LEFT JOIN estados_medicion e ON e.medicion_id = m.id';

if (['NORMAL', 'ALERTA', 'EMERGENCIA'].includes(token)) {
    msg.topic = baseJoin + " WHERE e.estado_riesgo='" + token + "' ORDER BY m.id DESC LIMIT 20";
} else if (token === 'RESUMEN_ALERTAS') {
    msg.topic = "SELECT estado_riesgo, COUNT(*) AS total, MAX(created_at) AS ultima_medicion FROM estados_medicion WHERE estado_riesgo IN ('ALERTA','EMERGENCIA') GROUP BY estado_riesgo ORDER BY total DESC";
} else if (token === 'RESUMEN_CALIDAD') {
    msg.topic = "SELECT limpio, COUNT(*) AS total, MAX(created_at) AS ultima_medicion FROM mediciones_brutas GROUP BY limpio ORDER BY limpio ASC";
} else if (token === 'BRUTAS_RECIENTES') {
    msg.topic = 'SELECT id, id_habitacion, contexto_hotel, temperatura_c, humedad_pct, fosfina_mq135, co_mq7, presencia_pir, intervalo_envio_ms, limpio, timestamp_origen, created_at FROM mediciones_brutas ORDER BY id DESC LIMIT 20';
} else if (token === 'INCIDENCIAS_RECIENTES') {
    msg.topic = 'SELECT id, medicion_id, id_habitacion, tipo_incidencia, detalle_incidencia, valor_detectado, created_at FROM incidencias ORDER BY id DESC LIMIT 20';
} else if (token === 'EVENTOS_RECIENTES') {
    msg.topic = 'SELECT id, medicion_id, id_habitacion, estado_riesgo, contexto_hotel, motivo_activacion, intervalo_objetivo_ms, timestamp_origen, created_at FROM eventos_actuadores ORDER BY id DESC LIMIT 20';
} else {
    msg.topic = baseJoin + ' ORDER BY m.id DESC LIMIT 20';
}

msg.queryType = 'select';
msg.payload = [];
return msg;

const estado = String(msg?.payload?.estado || '').toUpperCase();
const idHabitacion = String(msg?.payload?.id_habitacion || '').trim();
const validos = ['LIBRE', 'RESERVADA', 'FUMIGACION'];
if (!validos.includes(estado)) {
    node.warn('estado invalido: ' + estado);
    return null;
}
if (!idHabitacion) {
    node.warn('id_habitacion requerido para comando dirigido');
    return null;
}
flow.set('estado_habitacion', estado);
const baseTopic = env.get('TOPICO_COMANDOS') || 'alejandro.bravo_isa@uao.edu.co/comandos';
msg.topic = baseTopic;
msg.payload = { estado, id_habitacion: idHabitacion };
return msg;

msg.topic = 'SELECT id, id_habitacion, contexto_hotel, temperatura_c, humedad_pct, fosfina_mq135, co_mq7, presencia_pir, intervalo_envio_ms, timestamp_origen FROM mediciones_brutas WHERE limpio = 0 ORDER BY id ASC LIMIT 100';
msg.queryType = 'select_lote';
msg.payload = [];
return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [];
if (rows.length === 0) {
    msg.payload = 'Sin registros pendientes';
    return [null, msg];
}

const habitacionIds = [...new Set(rows.map((r) => String(r.id_habitacion || '').trim()).filter(Boolean))];
if (habitacionIds.length === 0) {
    msg.payload = 'Sin id_habitacion en lote';
    return [null, msg];
}

const safeIds = habitacionIds.map((v) => v.replace(/'/g, "''"));
msg.batchId = Date.now();
msg.batchRows = rows;
msg.topic = `SELECT id_habitacion, temperatura_c, humedad_pct, fosfina_mq135, co_mq7 FROM mediciones_brutas WHERE id_habitacion IN ('${safeIds.join("','")}') AND (temperatura_c IS NOT NULL OR humedad_pct IS NOT NULL OR fosfina_mq135 IS NOT NULL OR co_mq7 IS NOT NULL)`;
msg.queryType = 'select_stats';
return [msg, null];

const statsRows = Array.isArray(msg.payload) ? msg.payload : [];
const batchRows = Array.isArray(msg.batchRows) ? msg.batchRows : [];

if (batchRows.length === 0) {
    msg.payload = 'Sin registros en lote';
    return msg;
}

const statsByHabitacion = {};
const intervalCounts = {};

function ensureHabitacion(idHabitacion) {
    if (!statsByHabitacion[idHabitacion]) {
        statsByHabitacion[idHabitacion] = { values: {}, median: {}, intervalo_envio_ms: null };
    }
}

function pushVal(idHabitacion, field, value) {
    if (!Number.isFinite(value)) return;
    ensureHabitacion(idHabitacion);
    if (!statsByHabitacion[idHabitacion].values[field]) {
        statsByHabitacion[idHabitacion].values[field] = [];
    }
    statsByHabitacion[idHabitacion].values[field].push(value);
}

for (const r of statsRows) {
    const idHabitacion = String(r.id_habitacion || '').trim();
    if (!idHabitacion) continue;
    pushVal(idHabitacion, 'temperatura_c', Number(r.temperatura_c));
    pushVal(idHabitacion, 'humedad_pct', Number(r.humedad_pct));
    pushVal(idHabitacion, 'fosfina_mq135', Number(r.fosfina_mq135));
    pushVal(idHabitacion, 'co_mq7', Number(r.co_mq7));
}

for (const r of batchRows) {
    const idHabitacion = String(r.id_habitacion || '').trim();
    if (!idHabitacion) continue;
    const interval = Number(r.intervalo_envio_ms);
    if (!Number.isFinite(interval) || interval <= 0) continue;
    if (!intervalCounts[idHabitacion]) intervalCounts[idHabitacion] = {};
    const key = String(interval);
    intervalCounts[idHabitacion][key] = (intervalCounts[idHabitacion][key] || 0) + 1;
}

function median(values) {
    const arr = values.slice().sort((a, b) => a - b);
    const mid = Math.floor(arr.length / 2);
    if (arr.length === 0) return null;
    return arr.length % 2 === 0 ? (arr[mid - 1] + arr[mid]) / 2 : arr[mid];
}

function modeFromCounts(counts) {
    let best = null;
    let bestCount = 0;
    for (const [value, count] of Object.entries(counts || {})) {
        if (count > bestCount) {
            bestCount = count;
            best = value;
        }
    }
    return best !== null ? Number(best) : null;
}

for (const [idHabitacion, data] of Object.entries(statsByHabitacion)) {
    data.median.temperatura_c = median(data.values.temperatura_c || []);
    data.median.humedad_pct = median(data.values.humedad_pct || []);
    data.median.fosfina_mq135 = median(data.values.fosfina_mq135 || []);
    data.median.co_mq7 = median(data.values.co_mq7 || []);
    data.intervalo_envio_ms = modeFromCounts(intervalCounts[idHabitacion]);
    delete data.values;
}

const batchId = msg.batchId || Date.now();
flow.set('current_batch_id', batchId);
flow.set('batch_signatures', {});
msg.statsByHabitacion = statsByHabitacion;
msg.batchId = batchId;
msg.payload = batchRows;
return msg;

const row = msg.payload || {};
const statsByHabitacion = msg.statsByHabitacion || {};
const idHabitacion = String(row.id_habitacion || '').trim();
const contexto = String(row.contexto_hotel || '').trim().toUpperCase();
const rawTs = row.timestamp_origen;
const ts = new Date(rawTs);
const tsOk = Number.isFinite(ts.getTime());

const errors = [];
const errorCols = new Set();
const categories = new Set();
let fatal = false;
const measuredCols = new Set(['temperatura_c', 'humedad_pct', 'fosfina_mq135', 'co_mq7']);

function addError(code, col, category) {
    if (code && !errors.includes(code)) {
        errors.push(code);
    }
    if (category) categories.add(category);
    if (col && measuredCols.has(col)) errorCols.add(col);
}

if (!idHabitacion) {
    addError('id_habitacion_faltante', 'id_habitacion', 'INCOMPLETO');
    fatal = true;
}
if (!tsOk) {
    addError('timestamp_invalido', 'timestamp_origen', 'FORMATO');
    fatal = true;
}

const tempMin = Number(env.get('TEMP_MIN_C') || -20);
const tempMax = Number(env.get('TEMP_MAX_C') || 80);
const humMin = Number(env.get('HUM_MIN_PCT') || 0);
const humMax = Number(env.get('HUM_MAX_PCT') || 100);
const mq135Min = Number(env.get('MQ135_RAW_MIN') || 0);
const mq135Max = Number(env.get('MQ135_RAW_MAX') || 4095);
const mq7Min = Number(env.get('MQ7_RAW_MIN') || 0);
const mq7Max = Number(env.get('MQ7_RAW_MAX') || 4095);

function readNumeric(value, field, min, max, missingCode, formatCode, rangeCode) {
    if (value === null || value === undefined || value === '') {
        addError(missingCode, field, 'INCOMPLETO');
        return null;
    }
    const n = Number(value);
    if (!Number.isFinite(n)) {
        addError(formatCode, field, 'FORMATO');
        return null;
    }
    if (Number.isFinite(min) && n < min) {
        addError(rangeCode, field, 'ATIPICO');
        return null;
    }
    if (Number.isFinite(max) && n > max) {
        addError(rangeCode, field, 'ATIPICO');
        return null;
    }
    return n;
}

const temperatura = readNumeric(row.temperatura_c, 'temperatura_c', tempMin, tempMax, 'temperatura_faltante', 'temperatura_formato', 'temperatura_fuera_rango');
const humedad = readNumeric(row.humedad_pct, 'humedad_pct', humMin, humMax, 'humedad_faltante', 'humedad_formato', 'humedad_fuera_rango');
const fosfina = readNumeric(row.fosfina_mq135, 'fosfina_mq135', mq135Min, mq135Max, 'fosfina_mq135_faltante', 'fosfina_mq135_formato', 'fosfina_mq135_fuera_rango');
const co = readNumeric(row.co_mq7, 'co_mq7', mq7Min, mq7Max, 'co_mq7_faltante', 'co_mq7_formato', 'co_mq7_fuera_rango');

let presenciaPir = 0;
if (row.presencia_pir !== null && row.presencia_pir !== undefined && row.presencia_pir !== '') {
    const pirNum = Number(row.presencia_pir);
    if (Number.isFinite(pirNum)) {
        presenciaPir = pirNum > 0 ? 1 : 0;
    } else {
        addError('presencia_pir_formato', 'presencia_pir', 'FORMATO');
        presenciaPir = 0;
    }
}

let intervaloEnvio = null;
if (row.intervalo_envio_ms !== null && row.intervalo_envio_ms !== undefined && row.intervalo_envio_ms !== '') {
    const intervalNum = Number(row.intervalo_envio_ms);
    if (Number.isFinite(intervalNum)) {
        intervaloEnvio = intervalNum;
    } else {
        addError('intervalo_formato', 'intervalo_envio_ms', 'FORMATO');
    }
}

const habitacionStats = statsByHabitacion[idHabitacion] || {};
const expectedInterval = Number.isFinite(intervaloEnvio) && intervaloEnvio > 0
    ? intervaloEnvio
    : Number(habitacionStats.intervalo_envio_ms || env.get('TEMPORAL_INTERVALO_DEFAULT_MS') || 15000);

if (tsOk) {
    const lastKey = 'last_ts_limpieza_' + (idHabitacion || 'desconocido');
    const lastTs = Number(flow.get(lastKey) || 0);
    const gapMax = Number(env.get('TEMPORAL_GAP_MAX_MS') || 120000);
    const lossMax = Number(env.get('TEMPORAL_LOSS_MAX_MS') || Math.max(gapMax * 3, expectedInterval * 10));
    if (lastTs > 0) {
        const gap = ts.getTime() - lastTs;
        if (gap > lossMax) {
            addError('perdida_comunicacion_' + gap + 'ms', 'timestamp_origen', 'TEMPORAL');
        } else if (gap > gapMax) {
            addError('hueco_temporal_' + gap + 'ms', 'timestamp_origen', 'TEMPORAL');
        } else if (expectedInterval > 0 && Math.abs(gap - expectedInterval) > expectedInterval * 0.5) {
            addError('intervalo_irregular_' + gap + 'ms', 'timestamp_origen', 'TEMPORAL');
        }
    }
    flow.set(lastKey, ts.getTime());
}

const batchId = msg.batchId || flow.get('current_batch_id');
if (batchId && batchId !== flow.get('current_batch_id')) {
    flow.set('current_batch_id', batchId);
    flow.set('batch_signatures', {});
}
const batchSigs = flow.get('batch_signatures') || {};
const signature = [
    idHabitacion,
    contexto,
    tsOk ? ts.toISOString() : String(rawTs),
    Number.isFinite(temperatura) ? temperatura.toFixed(2) : 'NULL',
    Number.isFinite(humedad) ? humedad.toFixed(2) : 'NULL',
    Number.isFinite(fosfina) ? fosfina.toFixed(2) : 'NULL',
    Number.isFinite(co) ? co.toFixed(2) : 'NULL',
    presenciaPir,
    Number.isFinite(intervaloEnvio) ? intervaloEnvio : 'NULL'
].join('|');

if (batchSigs[signature]) {
    addError('duplicado_batch', 'duplicado', 'DUPLICADO');
} else {
    batchSigs[signature] = Date.now();
}
flow.set('batch_signatures', batchSigs);

const ttlMs = Number(env.get('DUP_SIG_TTL_MS') || 86400000);
const recentSigs = flow.get('recent_signatures') || {};
const now = Date.now();
for (const [sig, seenAt] of Object.entries(recentSigs)) {
    if ((now - seenAt) > ttlMs) {
        delete recentSigs[sig];
    }
}
if (recentSigs[signature]) {
    addError('duplicado_historico', 'duplicado', 'DUPLICADO');
}
recentSigs[signature] = now;
flow.set('recent_signatures', recentSigs);

const errorColumnCount = errorCols.size;
const imputedColumns = [];
const medians = habitacionStats && habitacionStats.median ? habitacionStats.median : {};

function impute(field, current) {
    if (Number.isFinite(current)) return current;
    const fallback = Number(medians[field]);
    if (Number.isFinite(fallback)) {
        imputedColumns.push(field);
        return Number(fallback);
    }
    addError('imputacion_sin_datos', field, 'ERROR');
    fatal = true;
    return current;
}

let cleanMsg = null;
if (!fatal && errorColumnCount <= 2) {
    const cleanData = {
        temperatura_c: impute('temperatura_c', temperatura),
        humedad_pct: impute('humedad_pct', humedad),
        fosfina_mq135: impute('fosfina_mq135', fosfina),
        co_mq7: impute('co_mq7', co),
        presencia_pir: presenciaPir,
        intervalo_envio_ms: intervaloEnvio,
        timestamp_origen: tsOk ? ts.toISOString().slice(0, 19).replace('T', ' ') : null
    };
    if (!fatal) {
        cleanMsg = {
            ...msg,
            cleanData,
            medicionesBrutasId: Number(row.id),
            idHabitacion,
            errors,
            errorColumns: Array.from(errorCols),
            imputedColumns
        };
    }
}

let incidenciaMsg = null;
if (errors.length > 0 || fatal) {
    let tipo = 'ERROR';
    if (categories.size === 1) {
        tipo = Array.from(categories)[0];
    } else if (categories.size > 1) {
        tipo = 'MULTIPLE';
    }
    const detalle = errors.join('; ').slice(0, 255);
    const valor = {
        errors,
        error_columns: Array.from(errorCols),
        imputed_columns: imputedColumns,
        id_habitacion: idHabitacion,
        timestamp_origen: rawTs,
        raw: {
            temperatura_c: row.temperatura_c,
            humedad_pct: row.humedad_pct,
            fosfina_mq135: row.fosfina_mq135,
            co_mq7: row.co_mq7,
            presencia_pir: row.presencia_pir,
            intervalo_envio_ms: row.intervalo_envio_ms
        }
    };
    incidenciaMsg = {
        ...msg,
        medicionesBrutasId: Number(row.id),
        idHabitacion,
        incidencia: {
            tipo,
            detalle,
            valor
        }
    };
}

return [cleanMsg, incidenciaMsg];

const data = msg.cleanData || {};
const medicionId = Number(msg.medicionesBrutasId);
if (!Number.isFinite(medicionId) || medicionId <= 0) {
    return null;
}

msg.topic = 'INSERT INTO mediciones_limpias (medicion_id, temperatura_c, humedad_pct, fosfina_mq135, co_mq7) VALUES (?, ?, ?, ?, ?)';
msg.payload = [
    medicionId,
    Number.isFinite(Number(data.temperatura_c)) ? Number(data.temperatura_c) : null,
    Number.isFinite(Number(data.humedad_pct)) ? Number(data.humedad_pct) : null,
    Number.isFinite(Number(data.fosfina_mq135)) ? Number(data.fosfina_mq135) : null,
    Number.isFinite(Number(data.co_mq7)) ? Number(data.co_mq7) : null
];
msg.queryType = 'insert_limpia';
return msg;

const inc = msg.incidencia || {};
const medicionId = Number(msg.medicionesBrutasId);
if (!Number.isFinite(medicionId) || medicionId <= 0) {
    return null;
}
const idHabitacion = String(msg.idHabitacion || 'DESCONOCIDO');
const tipo = String(inc.tipo || 'ERROR').toUpperCase();
const detalle = String(inc.detalle || 'incidencia_detectada').slice(0, 255);
const valor = JSON.stringify(inc.valor || {});

msg.topic = 'INSERT INTO incidencias (medicion_id, id_habitacion, tipo_incidencia, detalle_incidencia, valor_detectado) VALUES (?, ?, ?, ?, ?)';
msg.payload = [
    medicionId,
    idHabitacion,
    tipo,
    detalle,
    valor
];
msg.queryType = 'insert_incidencia';
return msg;

const medicionId = Number(msg.medicionesBrutasId);
if (!Number.isFinite(medicionId) || medicionId <= 0) {
    return null;
}
msg.topic = 'UPDATE mediciones_brutas SET limpio = 1 WHERE id = ?';
msg.payload = [medicionId];
msg.queryType = 'update_bruta';
return msg;

msg.topic = 'INSERT INTO analisis_mediciones (id_habitacion, temp_promedio, temp_minima, temp_maxima, hum_promedio, hum_minima, hum_maxima, temp_fuera_rango, hum_fuera_rango, total_registros, fecha_inicio_analisis, fecha_fin_analisis, fecha_generacion) SELECT b.id_habitacion, AVG(l.temperatura_c) AS temp_promedio, MIN(l.temperatura_c) AS temp_minima, MAX(l.temperatura_c) AS temp_maxima, AVG(l.humedad_pct) AS hum_promedio, MIN(l.humedad_pct) AS hum_minima, MAX(l.humedad_pct) AS hum_maxima, SUM(CASE WHEN l.temperatura_c < 18 OR l.temperatura_c > 25 THEN 1 ELSE 0 END) AS temp_fuera_rango, SUM(CASE WHEN l.humedad_pct < 30 OR l.humedad_pct > 60 THEN 1 ELSE 0 END) AS hum_fuera_rango, COUNT(*) AS total_registros, MIN(b.timestamp_origen) AS fecha_inicio_analisis, MAX(b.timestamp_origen) AS fecha_fin_analisis, NOW() AS fecha_generacion FROM mediciones_limpias l INNER JOIN mediciones_brutas b ON b.id = l.medicion_id WHERE b.timestamp_origen >= DATE_SUB(NOW(), INTERVAL 1 MONTH) GROUP BY b.id_habitacion';
msg.queryType = 'insert_analisis';
msg.payload = [];
return msg;
